import type { TextFieldProps } from ':components/TextField';
import type { InputMask } from 'imask';
import type { MutableRefObject } from 'react';
export interface NewMaskFieldProps extends Omit<TextFieldProps, 'onChange'> {
    /**
     * конфиг для маскирования ввода
     */
    maskConfig?: any;
    /**
     * пользовательский обработчик события onChange
     * тип ((event: ChangeEvent<HTMLInputElement>) => void) нужен для поддержки старой реализации
     */
    onChange?: (value: string, unmaskedValue: string, event: InputEvent) => void;
    /**
     * Callback для получения ссылки на maskRef для дополнительной кастомизации
     * Предоставляет доступ к методам IMask, таким как alignCursor, alignCursorFriendly и др.
     */
    onMaskRef?: (maskRef: MutableRefObject<InputMask<any> | null>) => void;
    /**
     * Callback, вызываемый при завершении ввода (когда маска полностью заполнена)
     * Срабатывает только для Pattern-based масок
     */
    onComplete?: (value: string, maskRef: InputMask<any>, event?: InputEvent) => void;
}
